// --- types.d.ts ---
// types.d.ts
export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: 'C' | 'F' | string;
  forecast: ForecastItem[];
}

export interface UseWeatherReturn {
  formattedTemp: string;
  formattedWind: string;
  formattedHumidity: string;
  forecastData: ForecastItem[];
  getTempString: (val: number) => string;
}

export interface CurrentWeatherProps {
  city: string;
  temp: string;
  condition: string;
  unit: string;
}

export interface WeatherDetailItemProps {
  label: string;
  value: string;
  icon?: string;
}

export interface ForecastDayProps {
  day: string;
  icon: string;
  high: string;
  low: string;
}

export interface ForecastStripProps {
  items: ForecastItem[];
  getTempString: (val: number) => string;
}

// --- constants.ts ---
// constants.ts — static data, mappings, configurations
// No React, no design system imports. Pure data only.

export const DEFAULT_UNIT = 'C' as const;

export const WEATHER_ICONS = {
  Sunny: '☀️',
  Cloudy: '☁️',
  Rainy: '🌧️',
  'Partly Cloudy': '⛅',
  Thunderstorm: '⛈️',
  Snow: '❄️',
} as const;

export const LABELS = {
  HUMIDITY: 'Humidity',
  WIND_SPEED: 'Wind Speed',
} as const;

export const UNIT_LABELS = {
  C: '°C',
  F: '°F',
} as const;

export const DEFAULT_CITY = 'San Francisco' as const;

export const DAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'] as const;

// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import type { Props, HookReturn } from './types';
import * as constants from './constants';

export function useComponent(props: Props): HookReturn {
  const {
    temperature,
    unit = 'C',
    humidity,
    windSpeed,
    forecast,
  } = props;

  const getTempString = useCallback(
    (val: number) => {
      return `${Math.round(val)}°${unit}`;
    },
    [unit]
  );

  return useMemo(() => ({
    formattedTemp: getTempString(temperature),
    formattedWind: `${windSpeed}${unit === 'F' ? ' mph' : ' km/h'}`,
    formattedHumidity: `${humidity}%`,
    forecastData: forecast,
    getTempString,
  }), [temperature, unit, humidity, windSpeed, forecast, getTempString]);
}


