// components/CurrentWeather.tsx — reusable sub-component
import React from 'react';
import { Card, Stack, Box, Divider, Text, Heading } from '@ggui-ai/design/primitives';
import type { WeatherCardProps } from './types';

export function CurrentWeather(props: WeatherCardProps) {
  const { city, temperature, condition, humidity, windSpeed, unit = 'C', forecast } = props;

  return (
    <div aria-label={`Current weather for ${city}`}>
      <Card padding={0}>
        <Box
          padding="var(--ggui-spacing-6)"
          background="var(--ggui-color-surfaceVariant)"
          borderRadius="var(--ggui-shape-radius-lg)"
        >
          <Stack gap="var(--ggui-spacing-6)">
            <Heading level={2}>{city}</Heading>

            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Stack direction="horizontal" align="center" justify="center" gap="var(--ggui-spacing-2)">
                <Heading level={1}>{temperature}</Heading>
                <Text variant="bodyLarge">°{unit}</Text>
              </Stack>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
                {condition}
              </Text>
            </Stack>

            <Stack direction="horizontal" justify="center" gap="var(--ggui-spacing-4)">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity: {humidity}%</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind: {windSpeed} km/h</Text>
            </Stack>

            <Divider margin="var(--ggui-spacing-4)" />

            <section style={{ width: '100%' }}>
              <Stack direction="horizontal" justify="between">
                {forecast.map((item, index) => (
                  <Stack key={index} align="center" gap="var(--ggui-spacing-1)">
                    <Text variant="caption">{item.day}</Text>
                    <Text size="lg">{item.icon}</Text>
                    <Text variant="label">{item.high}° / {item.low}°</Text>
                  </Stack>
                ))}
              </Stack>
            </section>
          </Stack>
        </Box>
      </Card>
    </div>
  );
}


