// components/WeatherDetails.tsx — reusable sub-component
import React from 'react';
import { Stack, Row, Text, Icon } from '@ggui-ai/design/primitives';
import type { WeatherDetailItemProps } from '../types';

export interface WeatherDetailsProps {
  humidity: string;
  windSpeed: string;
}

function WeatherDetailItem({ label, value, icon }: WeatherDetailItemProps) {
  return (
    <Stack align="center" gap="var(--ggui-spacing-1)">
      {icon && <Icon name={icon} size={20} />}
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
        {label}
      </Text>
      <Text variant="bodyLarge" color="var(--ggui-color-onSurface)">
        {value}
      </Text>
    </Stack>
  );
}

export function WeatherDetails({ humidity, windSpeed }: WeatherDetailsProps) {
  return (
    <Row justify="center" align="center" gap="var(--ggui-spacing-6)">
      <WeatherDetailItem
        icon="water_drop"
        label="Humidity"
        value={humidity}
      />
      <WeatherDetailItem
        icon="air"
        label="Wind Speed"
        value={windSpeed}
      />
    </Row>
  );
}


// --- components/ForecastStrip.tsx ---
import React from 'react';
import { Row, Stack, Text } from '@ggui-ai/design/primitives';
import type { ForecastStripProps } from '../types';

export function ForecastStrip({ items, getTempString }: ForecastStripProps) {
  return (
    <Row
      justify="between"
      align="center"
      style={{
        width: '100%',
        marginTop: 'var(--ggui-spacing-4, 16px)'
      }}
    >
      {items.map((item, index) => (
        <Stack
          key={`${item.day}-${index}`}
          align="center"
          gap="var(--ggui-spacing-1, 4px)"
        >
          <Text
            variant="caption"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {item.day}
          </Text>
          <Text size="xl">{item.icon}</Text>
          <Row gap="var(--ggui-spacing-1, 4px)">
            <Text variant="bodySmall" weight="bold">
              {getTempString(item.high)}
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {getTempString(item.low)}
            </Text>
          </Row>
        </Stack>
      ))}
    </Row>
  );
}


