import React from 'react';
import { Card, Stack, Row, Divider } from '@ggui-ai/design/primitives';
import { WeatherCardProps } from './types';
import { CurrentWeather, WeatherDetailItem, ForecastStrip } from './components';
import { useComponent as useWeather } from './hooks';

export function WeatherCard(props: WeatherCardProps) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast
  } = props;

  const {
    formattedTemp,
    formattedWind,
    formattedHumidity,
    getTempString
  } = useWeather({
    temperature,
    humidity,
    windSpeed,
    unit,
    forecast,
  });

  return (
    <div style={{ maxWidth: '400px' }}>
      <Card padding="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-6)">
          <CurrentWeather
            city={city}
            temp={formattedTemp}
            condition={condition}
            unit={unit}
          />

          <Row justify="between">
            <WeatherDetailItem label="Humidity" value={formattedHumidity} icon="droplet" />
            <WeatherDetailItem label="Wind Speed" value={formattedWind} icon="wind" />
          </Row>

          <Divider color="var(--ggui-color-outlineVariant)" margin={0} />

          <ForecastStrip items={forecast} getTempString={getTempString} />
        </Stack>
      </Card>
    </div>
  );
}

export { WeatherCard as Component };

